#include "Magazine.h"#include <iomanip>using namespace std;string Magazine::getEdition() const {    return edition;}string Magazine::getMainArticleTitle() const {    return mainArticleTitle;}void Magazine::setEdition(string edition) {    this->edition = edition;}void Magazine::setMainArticleTitle(string mainArticleTitle) {    this->mainArticleTitle = mainArticleTitle;}void Magazine::print(ostream& out) const {    const int LABEL_WIDTH = 18; // "Main Article Title" is the longest label    out << left << setw(LABEL_WIDTH) << "Item Type"          << ": Magazine" << endl;    out << left << setw(LABEL_WIDTH) << "Name"               << ": " << getName() << endl;    out << left << setw(LABEL_WIDTH) << "Description"        << ": " << getDescription() << endl;    out << left << setw(LABEL_WIDTH) << "ID"                 << ": " << getId() << endl;    out << left << setw(LABEL_WIDTH) << "Edition"            << ": " << edition << endl;    out << left << setw(LABEL_WIDTH) << "Main Article Title" << ": " << mainArticleTitle << endl;    if (isCheckedOut()) {        out << left << setw(LABEL_WIDTH) << "Status"      << ": Checked Out" << endl;        out << left << setw(LABEL_WIDTH) << "Borrowed By" << ": " << getBorrowName() << endl;        out << left << setw(LABEL_WIDTH) << "Due Date"    << ": " << getDueDate() << endl;    }    else {        out << left << setw(LABEL_WIDTH) << "Status" << ": Available" << endl;    }}